/**
 * @param {number[]} digitSum
 * @return {number}
 */
function solve(digitSum) {
    const MOD = 1000000007n;
    const MAX_VALUE = 5000;

    // Precompute all numbers up to MAX_VALUE and their digit sums.
    // valid_numbers[s] will store an array of numbers <= 5000 whose digit sum is s.
    const valid_numbers = Array(51).fill(0).map(() => []);

    for (let i = 0; i <= MAX_VALUE; i++) {
        let currentSum = 0;
        let temp = i;
        while (temp > 0) {
            currentSum += temp % 10;
            temp = Math.floor(temp / 10);
        }
        // Handle i=0 case: digit sum is 0
        if (i === 0 && currentSum === 0) {
            valid_numbers[0].push(0);
        } else if (i > 0) {
            valid_numbers[currentSum].push(i);
        }
    }

    // Sort the lists for easier processing, especially for non-decreasing constraint.
    for (let s = 0; s <= 50; s++) {
        valid_numbers[s].sort((a, b) => a - b);
    }

    const n = digitSum.length;

    // dp[i][j] will store the number of valid arrays of length i+1 
    // (i.e., for digitSum[0]...digitSum[i]) such that the last element arr[i] is equal to j.
    // Since the maximum value is 5000, we use an array indexed up to 5000.
    // The state space is too large for this direct DP approach if we use the value j.

    // Instead, let's change the DP state.
    // Let dp[i][k] be the number of valid prefixes of length i+1 
    // (satisfying digitSum[0]...digitSum[i]) such that arr[i] is the k-th smallest number 
    // in the list valid_numbers[digitSum[i]].

    // dp[i] will be an array where dp[i][j] is the count of valid prefixes 
    // ending with the j-th smallest number that satisfies digitSum[i].

    // Base case: i = 0 (first element)
    const d0 = digitSum[0];
    const candidates0 = valid_numbers[d0];
    const L0 = candidates0.length;

    // dp_prev[j] = count of valid arrays of length 1 ending with candidates0[j]
    let dp_prev = Array(L0).fill(1n);

    // Iterate from i = 1 to n-1
    for (let i = 1; i < n; i++) {
        const di = digitSum[i];
        const candidates_i = valid_numbers[di];
        const Li = candidates_i.length;

        // If no candidates exist for digitSum[i], the total count is 0.
        if (Li === 0) return 0;

        let dp_current = Array(Li).fill(0n);

        // For each candidate arr[i] = candidates_i[j]
        for (let j = 0; j < Li; j++) {
            const current_val = candidates_i[j];
            let current_count = 0n;

            // Sum up contributions from all previous valid prefixes 
            // where arr[i-1] <= arr[i] (i.e., candidates_prev[k] <= current_val).

            // We need to iterate over the previous DP states (dp_prev).
            // dp_prev corresponds to digitSum[i-1].

            // The previous candidates are valid_numbers[digitSum[i-1]].
            const candidates_prev = valid_numbers[digitSum[i-1]];

            // Find the maximum index k_max in candidates_prev such that candidates_prev[k_max] <= current_val.
            let k_max = -1;

            // Since candidates_prev is sorted, we can use binary search or linear scan.
            // Linear scan is fine given the constraints (max length 5000, but practical length is smaller).
            for (let k = 0; k < candidates_prev.length; k++) {
                if (candidates_prev[k] <= current_val) {
                    k_max = k;
                } else {
                    // Since it's sorted, we can break early
                    break;
                }
            }

            // Sum dp_prev[k] for k = 0 to k_max
            for (let k = 0; k <= k_max; k++) {
                current_count = (current_count + dp_prev[k]) % MOD;
            }

            dp_current[j] = current_count;
        }

        dp_prev = dp_current;
    }

    // Final result: sum up all counts in the last DP array (dp_prev)
    let total_count = 0n;
    for (const count of dp_prev) {
        total_count = (total_count + count) % MOD;
    }

    return Number(total_count);
}

