            while(low <= high) {
                val mid = low + (high - low) / 2
                if (candidatesPrev[mid] <= currentVal) {
                    bestK = mid
                    low = mid + 1 // Try to find a larger one
                } else {
                    high = mid - 1
                }
            }

            kMax = bestK

